// ============== Stable Product Linkage (Catatan #2) ==============
// SPH dihubungkan ke master produk via productId yang STABIL.
// Ini memastikan: saat nama/tipe/principal produk diedit, jumlah SPH TIDAK hilang.
// Karena link by ID, bukan by string modality::type.
// resolveProductId: cari product yang cocok untuk sebuah SPH (by existing productId, lalu fallback by modality+type)
const resolveProductId = (sph, productList) => {
  if (sph.productId) return sph.productId;
  const match = (productList || PRODUCT_MASTER_SEED).find(p => p.modality === sph.modality && p.type === sph.subModality);
  return match ? match.id : null;
};


const mk = (id, no, customer, ct, pt, mod, sub, qty, price, owner, region, stage, opts = {}) => {
  const baseProbs = { sph_sent: 20, presentation_scheduled: 35, presentation_done: 50, ecatalog: 40, negotiation: 70, tender: 55, po_issued: 100, lost: 0 };
  const scheme = opts.paymentScheme || detectPaymentScheme(pt, ct);
  return {
    id, sphNo: no, customer, customerType: ct, projectType: pt, modality: mod, subModality: sub,
    qty, unitPrice: price, totalValue: qty * price,
    issuedDate: opts.date || '2026-03-15',
    salesOwner: owner, region, status: opts.status || 'active', stage,
    tenderSubStage: opts.tenderSubStage || null,
    probability: opts.probability !== undefined ? opts.probability : baseProbs[stage],
    notes: opts.notes || '', nextAction: opts.nextAction || '-',
    lastUpdate: '2026-05-12',
    poStatus: stage === 'po_issued' ? 'issued' : null,
    dpPaid: !!opts.dpPaid, finalPaid: !!opts.finalPaid,
    shippingStatus: opts.shippingStatus || null,
    customsStatus: opts.customsStatus || null,
    customsStatusNote: opts.customsStatusNote || '',
    manifestId: opts.manifestId || null,
    // PAYMENT TRACKING (3 schemes)
    paymentScheme: scheme,
    dpPercent: opts.dpPercent !== undefined ? opts.dpPercent : (scheme === 'dp_installment' ? 30 : (scheme === 'kso' ? 10 : 0)),
    installmentMonths: opts.installmentMonths || (scheme === 'dp_installment' ? 12 : scheme === 'kso' ? 60 : 0),
    paymentHistory: opts.paymentHistory || [], // [{id, date, amount, type, note, recordedBy}]
    paymentNote: opts.paymentNote || '',
  };
};

