// ============== Uniform 6-Stage Regulatory Pipeline (Phase 2a) ==============
const REG_STAGES = ['docs', 'submit', 'eval', 'resubmit', 'pnbp', 'issued'];
const REG_STAGE_COLORS = {
  docs: '#94a3b8', submit: '#7d9cc5', eval: 'var(--ims-gold)',
  resubmit: '#c97b3f', pnbp: 'var(--ims-gold-dim)', issued: 'var(--ims-accent-2)',
};
const REG_STAGE_DATE_FIELD = {
  docs: 'docsDate', submit: 'submitDate', eval: 'evalDate',
  resubmit: 'resubmitDate', pnbp: 'pnbpDate', issued: 'issuedDate',
};
const REG_STAGES_DEFAULT = ['docs', 'submit', 'eval', 'resubmit', 'pnbp', 'issued'];
const REG_STAGES_AKL = ['docs', 'submit', 'pnbp', 'eval', 'resubmit', 'issued'];
const getRegStages = (recordType) => recordType === 'akl' ? REG_STAGES_AKL : REG_STAGES_DEFAULT;
const REG_AUTHORITY = {
  akl: 'Kemenkes', import: 'BAPETEN', pengalihan: 'BAPETEN',
  pi: 'BAPETEN', bapeten: 'BAPETEN',
};
const REG_PNBP_DEFAULT = {
  akl: 5000000, import: 12500000, pengalihan: 12500000,
  pi: 12500000, bapeten: 12500000,
};
const REG_PERMIT_PREFIX = {
  import: 'BAPETEN/IMP', pengalihan: 'BAPETEN/PGL',
  pi: 'BAPETEN/PI', bapeten: 'BAPETEN/PMF', akl: 'AKL',
};
const REG_TYPE_LABELS = {
  akl: { id: 'AKL Kemenkes', en: 'AKL Kemenkes' },
  import: { id: 'Izin Import', en: 'Import Permit' },
  pengalihan: { id: 'Izin Pengalihan', en: 'Transfer Permit' },
  pi: { id: 'Persetujuan Import (PI)', en: 'Import Approval (PI)' },
  bapeten: { id: 'Izin Pemanfaatan', en: 'Utilization Permit' },
};

function sanitizeRegStageHistory(history, stage, stages) {
  const rows = Array.isArray(history) ? history : [];
  const clean = rows
    .map((h) => {
      const to = stages.includes(h?.to) ? h.to : null;
      const from = !h?.from || stages.includes(h.from) ? (h?.from || null) : null;
      const ms = parseSafeDateMs(h?.at);
      if (!to || ms === null) return null;
      return { from, to, by: h?.by || 'migration', at: new Date(ms).toISOString() };
    })
    .filter(Boolean)
    .sort((a, b) => String(a.at || '').localeCompare(String(b.at || '')));
  if (clean.length === 0) return [{ from: null, to: stage, by: 'migration', at: new Date().toISOString() }];
  if (clean[clean.length - 1].to !== stage) {
    clean.push({ from: clean[clean.length - 1].to, to: stage, by: 'migration', at: new Date().toISOString() });
  }
  return clean;
}

function migrateRegRecord(rec, type) {
  if (!rec || typeof rec !== 'object') return rec;
  const stages = getRegStages(type);
  const next = { ...rec };
  const STAGE_REMAP = { preregist: 'docs', fix: 'resubmit' };
  let stage = next.stage;
  if (type === 'pi' && !stage) stage = 'issued';
  stage = STAGE_REMAP[stage] || stage || 'docs';
  if (!stages.includes(stage)) stage = 'docs';
  next.stage = stage;
  next.stageIdx = stages.indexOf(stage);
  if (rec._regV41 && Array.isArray(rec.stageHistory) && rec.stageHistory.length > 0) {
    next.stageHistory = sanitizeRegStageHistory(rec.stageHistory, stage, stages);
    next._regV41 = true;
    return next;
  }
  if (next.preregistDate && !next.docsDate) next.docsDate = next.preregistDate;
  if (next.fixDate && !next.resubmitDate) next.resubmitDate = next.fixDate;
  if (!Array.isArray(next.stageHistory) || next.stageHistory.length === 0) {
    const dateByStage = {
      docs: next.docsDate || next.preregistDate || next.registerDate,
      submit: next.submitDate, eval: next.evalDate,
      resubmit: next.resubmitDate || next.fixDate,
      pnbp: next.pnbpDate, issued: next.issuedDate,
    };
    const dated = [];
    for (const [st, d] of Object.entries(dateByStage)) {
      const t = parseSafeDateMs(d);
      if (t !== null) dated.push({ st, t, d });
    }
    dated.sort((a, b) => a.t - b.t);
    const hist = [];
    let prev = null;
    for (const item of dated) {
      if (stages.indexOf(item.st) > stages.indexOf(stage)) break;
      hist.push({ from: prev, to: item.st, by: 'migration', at: new Date(item.t).toISOString() });
      prev = item.st;
    }
    if (hist.length === 0) {
      hist.push({ from: null, to: stage, by: 'migration', at: new Date().toISOString() });
    } else if (hist[hist.length - 1].to !== stage) {
      hist.push({ from: hist[hist.length - 1].to, to: stage, by: 'migration', at: new Date().toISOString() });
    }
    next.stageHistory = hist;
  } else {
    next.stageHistory = sanitizeRegStageHistory(next.stageHistory, stage, stages);
  }
  next._regV41 = true;
  return next;
}

const IMPORT_PIPELINE_STEPS = [
  { id: 'plan_order', labelId: 'Pesanan Dibuat', labelEn: 'Order Created', color: '#94a3b8' },
  { id: 'factory_production', labelId: 'Barang Diproduksi/Disiapkan Pabrik', labelEn: 'Factory Production/Preparation', color: '#a026a0' },
  { id: 'ready_to_ship', labelId: 'Siap Kirim', labelEn: 'Ready to Ship', color: '#7d9cc5' },
  { id: 'on_shipment', labelId: 'Pengiriman', labelEn: 'Shipment', color: 'var(--ims-accent)' },
  { id: 'arrived_clearance', labelId: 'Tiba/Clearance', labelEn: 'Arrived/Clearance', color: '#5b87b8' },
  { id: 'sent_client', labelId: 'Dikirim ke Klien', labelEn: 'Sent to Client', color: '#2f8f6f' },
  { id: 'client_received', labelId: 'Diterima Klien', labelEn: 'Client Received', color: 'var(--ims-accent-2)' },
];

const LEGACY_IMPORT_STATUS_MAP = {
  planning: 'plan_order',
  loading: 'ready_to_ship',
  in_transit: 'on_shipment',
  arrived: 'arrived_clearance',
  cleared: 'arrived_clearance',
  delivered: 'sent_client',
  delivery_to_site: 'client_received',
};

function normalizeImportPipelineStatus(status) {
  return LEGACY_IMPORT_STATUS_MAP[status] || status || 'plan_order';
}

function importPipelineLabel(status, lang = 'id') {
  const normalized = normalizeImportPipelineStatus(status);
  const step = IMPORT_PIPELINE_STEPS.find(s => s.id === normalized);
  if (!step) return status || '-';
  return lang === 'id' ? step.labelId : step.labelEn;
}

function projectHasDpReceived(s) {
  return !!(s?.dpPaid || s?.dpConfirmedAt || s?.dpDecisionAt || ['dp_confirmed', 'factory_po_sent', 'factory_dp_paid', 'factory_production', 'factory_production_done'].includes(s?.sphWorkflowStatus));
}

function projectManifestText(s) {
  if (!s) return '';
  return normalizeProductLookupText([
    s.customer, s.sphNo, s.modality, s.productModality, s.subModality,
    s.productType, s.type, s.brand, s.productBrand, s.principal,
  ].filter(Boolean).join(' '));
}

function manifestSearchText(m) {
  if (!m) return '';
  return normalizeProductLookupText([
    m.manifestNo, m.customerName, m.sphNo, m.modality, m.typeBrand,
    m.principal, m.principalOrigin, m.notes,
  ].filter(Boolean).join(' '));
}

function manifestMatchesProject(manifest, project) {
  if (!manifest || !project) return false;
  if (manifest.linkedProjectId && manifest.linkedProjectId === project.id) return true;
  if (manifest.sphNo && project.sphNo && manifest.sphNo === project.sphNo) return true;
  if (project.manifestId && [manifest.id, manifest.manifestNo].includes(project.manifestId)) return true;
  const customer = normalizeProductLookupText(project.customer);
  const manifestCustomer = normalizeProductLookupText(manifest.customerName);
  return !!(customer && manifestCustomer && (customer === manifestCustomer || customer.includes(manifestCustomer) || manifestCustomer.includes(customer)));
}

// ============== Operations: Manifests & Customs Docs ==============
function generateSeedManifestsFromSph() {
  const ports = {
    China: ['Shanghai, China', 'Shanghai Port'],
    Korea: ['Busan, Korea', 'Busan Port'],
    Taiwan: ['Taipei, Taiwan', 'Keelung Port'],
  };
  return ALL_SPH.filter(projectHasDpReceived).map((s, i) => {
    const originKey = /Korea/i.test(s.origin || s.principal || '') ? 'Korea' : /Taiwan/i.test(s.origin || s.principal || '') ? 'Taiwan' : 'China';
    const [principalOrigin, portOfLoading] = ports[originKey] || ports.China;
    const status = normalizeImportPipelineStatus(s.shippingStatus || 'plan_order');
    return {
      id: `mfst_${s.id}`,
      manifestNo: `MFST-2026-${String(i + 1).padStart(3, '0')}`,
      linkedProjectId: s.id,
      customerName: s.customer,
      modality: s.modality,
      typeBrand: [s.subModality, s.productBrand || s.brand].filter(Boolean).join(' / '),
      sphNo: s.sphNo,
      principal: s.principal || s.partner || s.productBrand || '-',
      principalOrigin,
      shippingMode: i % 4 === 0 ? 'air' : 'sea',
      etd: i < 2 ? '' : `2026-05-${String(Math.min(28, 2 + i)).padStart(2, '0')}`,
      eta: i < 2 ? '' : `2026-05-${String(Math.min(28, 8 + i)).padStart(2, '0')}`,
      portOfLoading,
      portOfDischarge: 'Tanjung Priok, Jakarta',
      itemsCount: Number(s.qty) || 1,
      freightCost: Math.round((Number(s.totalValue) || 0) * 0.012),
      status,
      notes: `Manifest otomatis dari ${s.sphNo} - ${s.customer}`,
    };
  });
}

function generateSeedCustomsDocsFromSph(manifests) {
  return manifests
    .filter(m => ['on_shipment', 'arrived_clearance', 'sent_client', 'client_received'].includes(normalizeImportPipelineStatus(m.status)))
    .map((m, i) => {
      const project = ALL_SPH.find(s => s.id === m.linkedProjectId || s.sphNo === m.sphNo);
      const normalized = normalizeImportPipelineStatus(m.status);
      const status = ['sent_client', 'client_received'].includes(normalized) ? 'sppb'
        : normalized === 'arrived_clearance' ? 'pib_payment'
        : 'submitted';
      return {
        id: `cdoc_${m.id}`,
        docNo: status === 'sppb' ? `SPPB-2026-${String(i + 1).padStart(3, '0')}` : status === 'pib_payment' ? `PIB-2026-${String(i + 1).padStart(3, '0')}` : `BC-2026-${String(i + 1).padStart(3, '0')}`,
        manifestId: m.id,
        manifestNo: m.manifestNo,
        manifestRef: m.manifestNo,
        linkedProjectId: project?.id || m.linkedProjectId,
        customerName: m.customerName,
        modality: m.modality,
        typeBrand: m.typeBrand,
        sphNo: m.sphNo,
        principal: m.principal,
        shippingMode: m.shippingMode,
        eta: m.eta,
        docDate: m.eta || m.etd || '2026-05-10',
        status,
        pibAmount: status === 'pib_payment' ? Math.round((Number(project?.totalValue) || 0) * 0.018) : 0,
        fileUrl: '',
        notes: status === 'sppb' ? 'SPPB terbit, otomatis masuk Pengiriman Lokal/Gudang.'
          : status === 'pib_payment' ? 'Pembayaran PIB perlu diproses Finance.'
          : 'Dokumen customs diterima dan sedang diproses.',
      };
    });
}

const SEED_MANIFESTS = generateSeedManifestsFromSph();
const SEED_CUSTOMS_DOCS = generateSeedCustomsDocsFromSph(SEED_MANIFESTS);

