function flowStepDate(sph, step) {
  if (!sph || !step) return null;
  if (sph[step.date]) return sph[step.date];
  if (step.key === 'requested' && sph.sphRequestedAt) return sph.sphRequestedAt;
  if (step.key === 'admin_notified' && sph.sphRequestedAt) return sph.sphRequestedAt;
  if (step.key === 'client_po_info' && (sph.poIssuedAt || sph.poStatus === 'issued')) return sph.poIssuedAt || sph.lastUpdate;
  if (step.key === 'finance_po_notified' && (sph.poIssuedAt || sph.poStatus === 'issued')) return sph.financePoNotifiedAt || sph.poIssuedAt || sph.lastUpdate;
  if (step.key === 'dp_decision' && (sph.dpConfirmedAt || sph.dpFollowupAt || sph.dpClaimedAt)) return sph.dpConfirmedAt || sph.dpFollowupAt || sph.dpClaimedAt;
  if (step.key === 'principal_po_sent' && sph.principalPoStatus === 'sent') return sph.principalPoSentAt || sph.lastUpdate;
  if (step.key === 'factory_production' && (sph.factoryProductionStartedAt || sph.factoryProductionDoneAt)) return sph.factoryProductionStartedAt || sph.factoryProductionDoneAt;
  if (step.key === 'negotiation' && (sph.negotiationStartedAt || sph.tenderStartedAt || sph.ecatalogWaitingAt)) return sph.negotiationStartedAt || sph.tenderStartedAt || sph.ecatalogWaitingAt;
  if (step.key === 'installed_bast' && (sph.bastDate || sph.installationStatus === 'installed')) return sph.bastDate || sph.lastUpdate;
  return null;
}

function flowStepDone(sph, step) {
  if (flowStepDate(sph, step)) return true;
  return Array.isArray(sph?.stageHistory) && sph.stageHistory.some(h => h.to === step.key);
}

